const project = $('Load Project + Client').first().json;
const projectId = $('Receive Project').first().json.project_id;
const prevBriefingData = $('Load Existing Briefing').first().json;
const hasPrevBriefing = prevBriefingData && prevBriefingData.id;
const promptData = $('Load Agent Prompt').first().json;
const systemPrompt = (promptData && promptData.content)
  ? promptData.content
  : 'Eres el Agente de Briefing de un estudio de arquitectura tecnica. Convierte la informacion inicial del proyecto en un briefing estructurado. Responde EXCLUSIVAMENTE con un objeto JSON valido sin backticks ni texto adicional.';
const model = (promptData && promptData.model_recommended) || 'gpt-4o';
const temperature = (promptData && promptData.temperature !== null && promptData.temperature !== undefined) ? Number(promptData.temperature) : 0.2;
const nextVersion = hasPrevBriefing ? (prevBriefingData.version + 1) : 1;
const metadata = project.metadata || {};
const metaNotes = metadata.notes || metadata.description || '';
const budgetStr = project.budget_target ? project.budget_target + ' EUR' : 'No especificado';
const areaStr = project.property_area_m2 ? project.property_area_m2 + ' m2' : 'No especificada';
const locationParts = [project.location_address, project.location_city, project.location_province].filter(Boolean);
const locationStr = locationParts.length > 0 ? locationParts.join(', ') : 'No especificada';
const userParts = [
  'Genera el briefing estructurado para este proyecto.',
  '',
  'DATOS DEL PROYECTO:',
  '- Nombre: ' + (project.project_name || 'Sin nombre'),
  '- Tipo: ' + (project.project_type || 'No especificado'),
  '- Localizacion: ' + locationStr,
  '- Tipo de inmueble: ' + (project.property_type || 'No especificado'),
  '- Superficie aproximada: ' + areaStr,
  '- Presupuesto objetivo: ' + budgetStr + (project.budget_flexible ? ' (flexible)' : ' (ajustado)'),
  '- Urgencia: ' + (project.urgency || 'normal'),
  '',
  'DATOS DEL CLIENTE:',
  '- Nombre: ' + (project.client_name || 'Sin nombre'),
  '- Notas del cliente: ' + (project.client_notes || 'Sin notas'),
  '',
  'DESCRIPCION DEL ENCARGO:',
  metaNotes || 'Sin descripcion adicional'
];
if (hasPrevBriefing && prevBriefingData.status === 'revision_requested') {
  userParts.push('');
  userParts.push('BRIEFING ANTERIOR RECHAZADO (esta es la revision ' + nextVersion + '):');
  userParts.push('Resumen previo: ' + (prevBriefingData.summary || '').substring(0, 400));
  userParts.push('Corrige y mejora el briefing anterior basandote en el contexto disponible.');
}
userParts.push('');
userParts.push('Responde con el JSON estructurado del briefing.');
const userPrompt = userParts.join('\n');
return [{ json: {
  project_id: projectId,
  project_name: project.project_name,
  client_name: project.client_name,
  client_email: project.client_email || null,
  next_version: nextVersion,
  prompt_system: systemPrompt,
  prompt_user: userPrompt,
  model: model,
  temperature: temperature
} }];

const llmResult = $input.first().json;
const preparedData = $('Prepare LLM Payload').first().json;
let responseText = (llmResult.response_text || llmResult.content || '').trim();
if (responseText.startsWith('```')) {
  responseText = responseText.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim();
}
let parsed;
try {
  parsed = JSON.parse(responseText);
} catch(e) {
  parsed = null;
}
const isValid = parsed && typeof parsed.summary === 'string';
if (!isValid) {
  parsed = {
    summary: 'Error al procesar respuesta del LLM. Revisar manualmente. Respuesta: ' + responseText.substring(0, 200),
    client_needs: [],
    objectives: [],
    constraints: [],
    style_preferences: {},
    rooms_affected: [],
    missing_info: ['La respuesta del LLM no fue JSON valido'],
    open_questions: []
  };
}
return [{ json: {
  project_id: preparedData.project_id,
  project_name: preparedData.project_name,
  client_name: preparedData.client_name,
  client_email: preparedData.client_email,
  next_version: preparedData.next_version,
  summary: parsed.summary || '',
  client_needs: parsed.client_needs || [],
  objectives: parsed.objectives || [],
  constraints: parsed.constraints || [],
  style_preferences: parsed.style_preferences || {},
  rooms_affected: parsed.rooms_affected || [],
  missing_info: parsed.missing_info || [],
  open_questions: parsed.open_questions || []
} }];

const parsed = $('Parse Briefing Response').first().json;
const savedBriefing = $('Save Briefing').first().json;
const approvalRecord = $('Create Approval').first().json;
const resumeUrl = $execution.resumeUrl;
const approveUrl = resumeUrl + '?action=approve';
const rejectUrl = resumeUrl + '?action=reject';
const needsList = (parsed.client_needs || []).map(function(n) {
  const text = typeof n === 'object' && n !== null ? (n.need || JSON.stringify(n)) : String(n);
  return '<li>' + text + '</li>';
}).join('');
const objList = (parsed.objectives || []).map(function(o) { return '<li>' + String(o) + '</li>'; }).join('');
const missingList = (parsed.missing_info || []).map(function(m) { return '<li>' + String(m) + '</li>'; }).join('');
const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto">'
  + '<h2 style="color:#2c3e50">Studio AI — Revisión de Briefing</h2>'
  + '<h3 style="color:#7f8c8d">Proyecto: ' + parsed.project_name + '</h3>'
  + '<p><b>Cliente:</b> ' + parsed.client_name + ' &nbsp;|&nbsp; <b>Versión:</b> ' + parsed.next_version + '</p>'
  + '<hr style="border:none;border-top:1px solid #eee">'
  + '<h4>Resumen:</h4><p>' + parsed.summary + '</p>'
  + '<h4>Necesidades del cliente:</h4><ul>' + needsList + '</ul>'
  + '<h4>Objetivos:</h4><ul>' + objList + '</ul>'
  + '<h4>Información faltante:</h4><ul>' + missingList + '</ul>'
  + '<div style="margin:32px 0;text-align:center">'
  + '<a href="' + approveUrl + '" style="background:#27ae60;color:white;padding:14px 28px;text-decoration:none;border-radius:4px;margin-right:16px;display:inline-block;font-size:15px">&#10003; Aprobar Briefing</a>'
  + '<a href="' + rejectUrl + '" style="background:#e74c3c;color:white;padding:14px 28px;text-decoration:none;border-radius:4px;display:inline-block;font-size:15px">&#10007; Solicitar Revisión</a>'
  + '</div>'
  + '<p style="color:#95a5a6;font-size:12px;text-align:center">Este enlace expira en 72 horas.</p>'
  + '</div>';
return [{ json: {
  to: 'botelladesdeel98@gmail.com',
  subject: '[Studio AI] Briefing para revisión: ' + parsed.project_name,
  html_body: htmlBody,
  briefing_id: savedBriefing.id,
  approval_id: approvalRecord.id,
  project_id: parsed.project_id,
  project_name: parsed.project_name,
  next_version: parsed.next_version
} }];

const resumeData = $input.first().json;
const emailData = $('Build Approval Email').first().json;
const action = (resumeData.query && resumeData.query.action)
  || (resumeData.body && resumeData.body.action)
  || resumeData.action
  || 'reject';
return [{ json: {
  action: action,
  is_approved: action === 'approve',
  project_id: emailData.project_id,
  briefing_id: emailData.briefing_id,
  approval_id: emailData.approval_id,
  project_name: emailData.project_name,
  next_version: emailData.next_version
} }];
